// 将文档中所有表格内的文字设置为水平居中和垂直居中
var doc = Application.ActiveDocument;
var tables = doc.Tables;
var count = tables.Count;
for (var i = 0; i < count; i++) {
    var table = tables.Item(i);
    var cells = table.Range.Cells;
    for (var j = 0; j < cells.Count; j++) {
        var cell = cells.Item(j);
        cell.HorizontalAlign = 1; // 1 表示居中
        cell.VerticalAlign = 2;   // 2 表示垂直居中
    }
}
return "已完成：" + count + " 个表格内的文字已设置为水平和垂直居中。";

// 将文档中所有表格内的文字设置为水平居中和垂直居中
var doc = Application.ActiveDocument;
var tables = doc.Tables;
var count = tables.Count;
for (var i = 1; i <= count; i++) {
    var table = tables.Item(i - 1);
    var range = table.Range;
    range.ParagraphFormat.Alignment = 1; // 1 表示居中
}
return "已完成：" + count + " 个表格内的文字已设置为水平居中。";

// 将文档内所有公式及公式编号段落设置为左对齐
var doc = Application.ActiveDocument;
var range = doc.Range();
range.SelectAll();
var paragraphs = range.Paragraphs;
for (var i = 0; i < paragraphs.Count; i++) {
    var para = paragraphs.Item(i + 1);
    // 简单判断：包含等号或常见公式符号的段落视为公式，末尾含右括号数字的视为公式编号
    var text = para.Range.Text.trim();
    if ((text.indexOf("=") >= 0 || text.indexOf("√") >= 0 || text.indexOf("∑") >= 0 || text.indexOf("∫") >= 0) || /\)\s*\d+\s*$/.test(text)) {
        para.Range.ParagraphFormat.Alignment = 0; // 0=左对齐
    }
}
return "公式及编号左对齐完成";

// 将文档内所有公式及公式编号段落设置为左对齐
var doc = Application.ActiveDocument;
var paragraphs = doc.Paragraphs;
for (var i = 1; i <= paragraphs.Count; i++) {
    var para = paragraphs.Item(i);
    var text = para.Range.Text.replace(/\r\n/g, '').trim();
    if ((text.indexOf("=") >= 0 || text.indexOf("√") >= 0 || text.indexOf("∑") >= 0 || text.indexOf("∫") >= 0) || /\)\s*\d+\s*$/.test(text)) {
        para.Range.ParagraphFormat.Alignment = 0;
    }
}
return "公式及编号左对齐完成";
